When the site runs on **self-hosted Postgres** (no Supabase Auth/GoTrue service), `supabase.auth.signInWithPassword()` and all other `supabase.auth.*` methods will **always fail silently** because there's no GoTrue REST API serving them.

## Detection

Check if Supabase Auth service is running:
```bash
docker ps | grep -iE 'gotrue|supabase-auth|kong'
# Empty output -> no Supabase Auth
```

## ⚠️ CRITICAL: supabase-js CANNOT talk to raw Postgres

`@supabase/supabase-js` sends REST API calls to `{SUPABASE_URL}/rest/v1/...` — **not** PostgreSQL wire protocol. When `NEXT_PUBLIC_SUPABASE_URL` points to a raw Postgres port (5432), ALL queries via `supabase.from('table').select()` silently fail with:
```
TypeError: fetch failed
Caused by: SocketError: other side closed (UND_ERR_SOCKET)
```

**Do NOT use supabase-js for server-side auth APIs.** Use `pg` (node-postgres) directly with `Pool` connections.

## Pre-requisites

```bash
pnpm add pg bcryptjs jsonwebtoken jose
pnpm add -D @types/bcryptjs @types/jsonwebtoken
```

## Full Pattern: Custom Auth API Routes

### 1. Install Dependencies

```bash
pnpm add bcryptjs jsonwebtoken jose
pnpm add -D @types/bcryptjs @types/jsonwebtoken
```

### 2. Database: Add password_hash Column

```sql
ALTER TABLE customers ADD COLUMN IF NOT EXISTS password_hash text;
```

### 3. Auth API Routes

Create three endpoints under `src/app/api/auth/`:

#### POST /api/auth/login

```ts
// src/app/api/auth/login/route.ts
// @ts-nocheck
import { NextRequest, NextResponse } from 'next/server';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'change-in-production';
const TOKEN_EXPIRY = '7d';

async function query(sql: string, params: any[] = []) {
  const { Pool } = require('pg');
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    max: 5,
    connectionTimeoutMillis: 5000,
  });
  try {
    const client = await pool.connect();
    try {
      const result = await client.query(sql, params);
      return result.rows;
    } finally { client.release(); }
  } finally { await pool.end(); }
}

export async function POST(request: NextRequest) {
  try {
    const { email, password } = await request.json();
    if (!email?.trim() || !password) {
      return NextResponse.json({ error: 'Email y contraseña son requeridos' }, { status: 400 });
    }

    const customers = await query('SELECT * FROM customers WHERE email = $1 LIMIT 1', [email.trim().toLowerCase()]);
    if (!customers.length) return NextResponse.json({ error: 'Credenciales incorrectas.' }, { status: 401 });

    const customer = customers[0];
    if (!customer.password_hash) return NextResponse.json({ error: 'Esta cuenta usa otro método.' }, { status: 401 });

    const bcrypt = require('bcryptjs');
    if (!(await bcrypt.compare(password, customer.password_hash))) {
      return NextResponse.json({ error: 'Credenciales incorrectas.' }, { status: 401 });
    }

    await query('UPDATE customers SET last_login_at = NOW() WHERE id = $1', [customer.id]);

    const token = jwt.sign(
      { sub: customer.id, email: customer.email, role: 'customer' },
      JWT_SECRET,
      { expiresIn: TOKEN_EXPIRY }
    );

    return NextResponse.json({
      access_token: token,
      user: { id: customer.id, email: customer.email, full_name: customer.full_name, phone: customer.phone },
    });
  } catch (error) {
    console.error('[auth/login] error:', error);
    return NextResponse.json({ error: 'Error de conexión.' }, { status: 500 });
  }
}
```

#### POST /api/auth/register

```ts
// src/app/api/auth/register/route.ts
// Same query() helper as login
import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  try {
    const { email, password, full_name, phone } = await request.json();
    // Validate: email required, password min 6 chars, full_name required
    if (!email?.trim()) return NextResponse.json({ error: 'El correo es obligatorio' }, { status: 400 });
    if (!password || password.length < 6) return NextResponse.json({ error: 'Mínimo 6 caracteres' }, { status: 400 });
    if (!full_name?.trim()) return NextResponse.json({ error: 'El nombre es obligatorio' }, { status: 400 });

    // Check duplicate
    const existing = await query('SELECT id FROM customers WHERE email = $1 LIMIT 1', [email.trim().toLowerCase()]);
    if (existing.length > 0) return NextResponse.json({ error: 'Ya registrado.' }, { status: 409 });

    const bcrypt = require('bcryptjs');
    const crypto = require('crypto');
    const password_hash = await bcrypt.hash(password, 12);
    const id = crypto.randomUUID();
    const displayName = full_name.trim().split(' ')[0];

    await query(
      `INSERT INTO customers (id, email, full_name, phone, password_hash, display_name, created_at)
       VALUES ($1, $2, $3, $4, $5, $6, NOW())`,
      [id, email.trim().toLowerCase(), full_name.trim(), phone?.trim() || null, password_hash, displayName]
    );

    return NextResponse.json({ success: true, message: 'Cuenta creada.' });
  } catch (error) {
    console.error('[auth/register] error:', error);
    return NextResponse.json({ error: 'Error al crear la cuenta.' }, { status: 500 });
  }
}
```

#### GET /api/auth/me

```ts
// src/app/api/auth/me/route.ts - same query() helper
import { jwtVerify } from 'jose';

export async function GET(request: NextRequest) {
  const authHeader = request.headers.get('authorization');
  const token = authHeader?.startsWith('Bearer ') ? authHeader.slice(7) : null;
  if (!token) return NextResponse.json({ error: 'No autorizado' }, { status: 401 });

  try {
    const { payload } = await jwtVerify(token, new TextEncoder().encode(JWT_SECRET));
    const rows = await query('SELECT * FROM customers WHERE id = $1 LIMIT 1', [payload.sub]);
    if (!rows.length) return NextResponse.json({ error: 'No encontrado' }, { status: 404 });
    const c = rows[0];
    return NextResponse.json({ id: c.id, email: c.email, full_name: c.full_name, phone: c.phone });
  } catch {
    return NextResponse.json({ error: 'Token inválido' }, { status: 401 });
  }
}
```

