### 5. Update Middleware

Replace `@supabase/ssr` with `jose` for middleware auth check:

```ts
// src/middleware.ts
import { jwtVerify } from 'jose';
const JWT_SECRET = new TextEncoder().encode(process.env.JWT_SECRET || 'change-in-production');

export async function middleware(request: NextRequest) {
  const pathname = request.nextUrl.pathname;
  if (!pathname.startsWith('/admin')) return NextResponse.next({ request });
  if (pathname === '/admin/ingreso' || pathname.startsWith('/_next/') || pathname.startsWith('/api/')) {
    return NextResponse.next({ request });
  }

  const authHeader = request.headers.get('authorization');
  const token = authHeader?.startsWith('Bearer ') ? authHeader.slice(7) : request.cookies.get('fun4me_token')?.value;

  if (!token) { /* redirect to /admin/ingreso */ }
  try { await jwtVerify(token, JWT_SECRET); return NextResponse.next({ request }); }
  catch { /* redirect to /admin/ingreso */ }
}

export const config = { matcher: ['/admin/:path*'] };
```

